oxy_webhelp_navlinks = {"mssql_multi_data_center_avail_grp-d30753e30384":{"topics":[{"title":"Prerequisites for multi-data center availability groups","shortdesc":"<p class=\"shortdesc\">Microsoft SQL Server hosts and Rubrik clusters must meet the following requirements         before they can support multi-data center availability groups.<\/p>","href":"saas\/mssql_prereqs_multi_data_center_ag.html","attributes":{"data-id":"mssql_prereqs_multi_data_center_ag"},"menu":{"hasChildren":false},"tocID":"mssql_prereqs_multi_data_center_ag-d30753e30395","topics":[]},{"title":"Creating a bidirectional replication SLA Domain","shortdesc":"<p class=\"shortdesc\">Create a bidirectional replication SLA Domain for multi-data center availability         groups that span two Rubrik clusters to manage protection for primary and secondary database         replicas for both clusters.<\/p>","href":"saas\/mssql_creating_bidi_repl_sla_domain.html","attributes":{"data-id":"mssql_creating_bidi_repl_sla_domain"},"menu":{"hasChildren":false},"tocID":"mssql_creating_bidi_repl_sla_domain-d30753e30406","topics":[]},{"title":"Linking multi-data center availability groups","shortdesc":"<p class=\"shortdesc\">Link two multi-data center availability groups to a bidirectional SLA Domain that         spans two Rubrik clusters. This configuration enables the SLA Domain to manage protection         for primary and secondary database replicas located in different data centers.<\/p>","href":"saas\/mssql_linking_multi_dc_ags.html","attributes":{"data-id":"mssql_linking_multi_dc_ags"},"menu":{"hasChildren":false},"tocID":"mssql_linking_multi_dc_ags-d30753e30417","topics":[]},{"title":"Linking multi-data center availability group databases","shortdesc":"<p class=\"shortdesc\">Link individual databases from two multi-data center availability groups to a         bidirectional SLA Domain that spans two Rubrik clusters. This configuration enables the SLA         Domain to manage protection for primary and secondary database replicas located in different         data centers.<\/p>","href":"saas\/mssql_linking_multi_dc_ag_dbs.html","attributes":{"data-id":"mssql_linking_multi_dc_ag_dbs"},"menu":{"hasChildren":false},"tocID":"mssql_linking_multi_dc_ag_dbs-d30753e30428","topics":[]},{"title":"Recovering multi-data center availability groups","shortdesc":"<p class=\"shortdesc\">Recover a multi-data center availability group database by exporting a Microsoft SQL         Server instance, including its underlying databases, to a specific point in         time.<\/p>","href":"saas\/mssql_recovering_multi_dc_avail_grp.html","attributes":{"data-id":"mssql_recovering_multi_dc_avail_grp"},"menu":{"hasChildren":false},"tocID":"mssql_recovering_multi_dc_avail_grp-d30753e30439","topics":[]},{"title":"Unlinking multi-data center availability groups","shortdesc":"<p class=\"shortdesc\">Unlink multi-data center availability groups from a bidirectional SLA Domain when         protection for primary and secondary database replicas for both Rubrik clusters is no longer         needed.<\/p>","href":"saas\/mssql_unlinking_multi_dc_avail_grp.html","attributes":{"data-id":"mssql_unlinking_multi_dc_avail_grp"},"menu":{"hasChildren":false},"tocID":"mssql_unlinking_multi_dc_avail_grp-d30753e30450","topics":[]}]}};